import React from "react";
import { Card, Col, Row } from "react-bootstrap";
import {
  getAllSocialAccounts,
  getCityAndState,
  getEmail,
  getFullName,
  getProfile,
} from "../../utilities";
import { SocialAccount } from "../common/SocialAccount";
import { TextIcon } from "../common/TextIcon";

export const Introduction = () => {
  const name = getFullName();
  const profile = getProfile();
  const city = getCityAndState();
  const email = getEmail();

  return (
    <>
      <Card className="text-center" border="light">
        <Card.Body>
          <Row>
            <Col>
              <Card.Title>
                <p className="h1" style={{ fontWeight: "bolder" }}>
                  {name.toUpperCase()}
                </p>
              </Card.Title>
              <Card.Subtitle>
                <p className="h5 text-muted">{profile}</p>
              </Card.Subtitle>
              <Card.Text style={{ paddingBottom: "0.5rem" }}>
                <TextIcon name="at" size="sm" text={email} />
                <TextIcon name="map-marker-alt" size="sm" text={city} />
              </Card.Text>
            </Col>
          </Row>
          <Row>
            <Col>
              <Card.Text>
                {getAllSocialAccounts().map((item) => (
                  <SocialAccount key={`social-${item.rank}`} social={item} />
                ))}
              </Card.Text>
            </Col>
          </Row>
        </Card.Body>
      </Card>
    </>
  );
};
