import { Badge, Container } from "react-bootstrap";
import Education from "../Education";
import Introduction from "../Introduction";
import WorkHistory from "../WorkHistory";

const getBreakpointName = () => {
  const screen = window.screen;

  if (screen.width < 576) {
    return "xs";
  }

  if (screen.width >= 1400) {
    return "xxl";
  }

  if (screen.width >= 1200) {
    return "xl";
  }

  if (screen.width >= 992) {
    return "lg";
  }

  if (screen.width >= 768) {
    return "md";
  }

  if (screen.width >= 576) {
    return "sm";
  }
};

export const App = () => {
  return (
    <>
      <Container style={{ paddingTop: "2rem" }}>
        <div>
          <Badge style={{ marginBottom: "0.25rem" }} pill variant={"primary"}>
            {getBreakpointName()}
          </Badge>
        </div>
        <Introduction />
        <Education />
        {/* <WorkHistory /> */}
      </Container>
    </>
  );
};
